// Pre-construction des Path2D (une seule fois au chargement)
const HORSE_VECTOR_ASSETS = HORSE_FRAMES.map(fr => fr.map(o => ({ r:o.r, s:o.s, c:o.c, p:new Path2D(o.d) })));

function adjustColorBrightness(hex, pct){
  const h=hex.replace('#','');
  const r=parseInt(h.slice(0,2),16),g=parseInt(h.slice(2,4),16),b=parseInt(h.slice(4,6),16);
  const f=1+pct/100, c=v=>Math.max(0,Math.min(255,Math.round(v*f)));
  return `rgb(${c(r)},${c(g)},${c(b)})`;
}
function horseLayerColor(o, horseColor, jockeyColor){
  if(o.r==='coat')   return o.s==='base'?horseColor :o.s==='dark'?adjustColorBrightness(horseColor,-45):adjustColorBrightness(horseColor,18);
  if(o.r==='jacket') return o.s==='base'?jockeyColor:o.s==='dark'?adjustColorBrightness(jockeyColor,-30):adjustColorBrightness(jockeyColor,22);
  return o.c; // fixed
}

/* Dessine un cheval vectoriel.
   x = centre horizontal, y = ligne des sabots (sol)
   scale = echelle (perspective 2.5D)
   frameIndex = index du cycle (modulo 10 en interne)
   horseColor = robe (hex), jockeyColor = casaque+bride (hex) */
function drawHorseSprite(ctx, x, y, scale, frameIndex, horseColor, jockeyColor){
  const n=HORSE_META.nframes;
  const layers=HORSE_VECTOR_ASSETS[((frameIndex%n)+n)%n];
  ctx.save();
  ctx.translate(x,y); ctx.scale(scale,scale); ctx.translate(-HORSE_META.anchorX,-HORSE_META.anchorY);
  for(const o of layers){ ctx.fillStyle=horseLayerColor(o,horseColor,jockeyColor); ctx.fill(o.p); }
  ctx.restore();
}

/* CADENCE: 22 fps -> avancer d'une frame toutes les ~45ms.
   Dans la boucle de course:
     horse.frameTimer += dt;
     if(horse.frameTimer >= 1000/HORSE_META.fps){ horse.frame=(horse.frame+1)%HORSE_META.nframes; horse.frameTimer=0; }
   Desync: initialiser horse.frame a un offset aleatoire (0..9). */
